import mysql.connector

def import_data(file_path):
    # Validate file path to prevent directory traversal attacks
    if not file_path.startswith('/safe/directory/'):
        raise ValueError("Invalid file path")

    try:
        # Connect to the MySQL database with local_infile enabled
        conn = mysql.connector.connect(
            host="localhost",
            user="your_username",
            password="your_password",
            database="your_database",
            allow_local_infile=True
        )
        cursor = conn.cursor()

        # Construct the LOAD DATA INFILE statement
        query = f"LOAD DATA INFILE '{file_path}' INTO TABLE your_table"

        # Execute the query
        cursor.execute(query)
        conn.commit()
        print("Data imported successfully")

    except mysql.connector.Error as err:
        print(f"Error: {err}")

    finally:
        if conn.is_connected():
            cursor.close()
            conn.close()

if __name__ == "__main__":
    file_path = input("Enter the file path to import: ")
    import_data(file_path)